def token_f1(target_tokens, text):
    ntokens = normalize_arabic(text).split()
    if not ntokens:
        return 0.0
    # compute precision and recall
    target_set = collections.Counter(target_tokens)
    ntoken_counts = collections.Counter(ntokens)
    # compute overlap counts
    overlap = 0
    for t,c in target_set.items():
        overlap += min(c, ntoken_counts.get(t,0))
    precision = overlap / max(1,sum(ntoken_counts[t] for t in target_set))  # restrict to appeared tokens?
    recall = overlap / len(target_tokens)
    if precision + recall == 0:
        return 0.0
    return 2 * precision * recall / (precision + recall)

